INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.414, 1, "2030/01/01 14:59:59", 1000001, 0.0, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 190805, "カリン", 62, 1, -416.5, 1, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.099, 1, "2030/01/01 14:59:59", 1000002, 0.0, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 190805, "カリン", 62, 1, -416.5, 2, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.801, 1, "2030/01/01 14:59:59", 1000003, 0.0, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", 190805, "カリン", 63, 1, -416.5, 3, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (0.0, 2, "2030/01/01 14:59:59", 1000004, 0.0, 2, "報酬がもらえますよ！\nチェックしてみてください", 190805, "カリン", 63, 1, -416.5, 4, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.12, 2, "2030/01/01 14:59:59", 1000005, 0.0, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 190805, "カリン", 64, 1, -363.0, 5, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1.68, 1, "2030/01/01 14:59:59", 1000006, 0.0, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 190805, "カリン", 64, 1, -363.0, 6, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.33, 2, "2030/01/01 14:59:59", 1000007, 0.0, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 190805, "カリン", 64, 1, -363.0, 7, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.18, 3, "2030/01/01 14:59:59", 1020101, -6.0, 7, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 133701, "ラビリスタ", 61, 10201, -285.0, 101, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.77, 1, "2030/01/01 14:59:59", 1020102, -2.0, 2, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 133901, "クリスティーナ", 61, 10201, -285.0, 201, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (15.5, 6, "2030/01/01 14:59:59", 1020103, 0.0, 1, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 133801, "ネネカ", 61, 10201, -285.0, 301, "2025/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (9.061, 2, "2030/01/01 14:59:59", 1020201, 0.0, 5, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 134301, "ランファ", 61, 10202, -285.0, 101, "2025/02/28 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.699, 1, "2030/01/01 14:59:59", 1020202, 0.0, 2, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 134401, "チカ", 61, 10202, -285.0, 201, "2025/02/28 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.595, 1, "2030/01/01 14:59:59", 1020301, 0.0, 2, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 134601, "アオイ", 61, 10203, -285.0, 101, "2025/03/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.758, 1, "2030/01/01 14:59:59", 1020302, 0.0, 2, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 134501, "クローチェ", 61, 10203, -285.0, 201, "2025/03/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.0, 2, "2030/01/01 14:59:59", 1020401, 0.0, 6, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 132302, "ルイズマリー", 61, 10204, -285.0, 101, "2025/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.904, 1, "2030/01/01 14:59:59", 1020402, 0.0, 2, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 132402, "イロハ", 61, 10204, -285.0, 201, "2025/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.487, 4, "2030/01/01 14:59:59", 1020403, 0.0, 2, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 132502, "ソノ", 61, 10204, -285.0, 301, "2025/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.763, 1, "2030/01/01 14:59:59", 1020502, 0.0, 2, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 134901, "カノン", 61, 10205, -285.0, 101, "2025/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.417, 1, "2030/01/01 14:59:59", 1020503, 0.0, 3, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 134801, "ツムギ", 61, 10205, -285.0, 201, "2025/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (10.335, 3, "2030/01/01 14:59:59", 1020601, 0.0, 7, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 135001, "エリス", 61, 10206, -285.0, 101, "2025/06/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.281, 2, "2030/01/01 14:59:59", 1020602, 0.0, 4, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 135101, "シェフィ", 61, 10206, -285.0, 201, "2025/06/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (12.244, 1, "2030/01/01 14:59:59", 1020603, 0.0, 2, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 135201, "プレシア", 61, 10206, -285.0, 301, "2025/06/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.339, 2, "2030/01/01 14:59:59", 1020701, 0.0, 8, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 135301, "クリア", 61, 10207, -285.0, 101, "2025/07/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.184, 7, "2030/01/01 14:59:59", 1020702, 0.0, 9, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 135401, "アネモネ", 61, 10207, -285.0, 201, "2025/07/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.906, 9, "2030/01/01 14:59:59", 1020801, 0.0, 2, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 129101, "アイラ", 61, 10208, -285.0, 101, "2025/08/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (14.465, 1, "2030/01/01 14:59:59", 1020802, 0.0, 2, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 129201, "シナツ", 61, 10208, -285.0, 201, "2025/08/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.662, 4, "2030/01/01 14:59:59", 1020803, 0.0, 3, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 100101, "ヒヨリ", 61, 10208, -285.0, 301, "2025/08/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (10.915, 1, "2030/01/01 14:59:59", 1020804, 0.0, 3, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 100301, "レイ", 61, 10208, -285.0, 401, "2025/08/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.042, 1, "2030/01/01 14:59:59", 1020901, 0.0, 7, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 135802, "ユキノ", 61, 10209, -285.0, 101, "2025/09/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (9.402, 4, "2030/01/01 14:59:59", 1020902, 0.0, 1, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 135903, "サツキ", 61, 10209, -285.0, 201, "2025/09/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.16, 8, "2030/01/01 14:59:59", 1020903, 0.0, 1, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 136902, "ルルィ", 61, 10209, -285.0, 301, "2025/09/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.0, 3, "2030/01/01 14:59:59", 1021001, 0.0, 2, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 137401, "カスミ", 61, 10210, -285.0, 101, "2025/10/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.12, 4, "2030/01/01 14:59:59", 1021002, 0.0, 1, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 136001, "アラクネ", 61, 10210, -285.0, 201, "2025/10/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.386, 4, "2030/01/01 14:59:59", 1021003, 0.0, 2, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 136202, "ナーナ", 61, 10210, -285.0, 301, "2025/10/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.438, 3, "2030/01/01 14:59:59", 1021101, 0.0, 4, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 136402, "ユイ", 61, 10211, -285.0, 101, "2025/11/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.35, 1, "2030/01/01 14:59:59", 1021102, 0.0, 5, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 136302, "ミソラ", 61, 10211, -285.0, 201, "2025/11/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.0, 1, "2030/01/01 14:59:59", 1021201, 0.0, 2, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 136501, "シズル", 61, 10212, -285.0, 101, "2025/12/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.25, 1, "2030/01/01 14:59:59", 1021202, 0.0, 2, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 137902, "リノ", 61, 10212, -285.0, 201, "2025/12/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.5, 1, "2030/01/01 14:59:59", 1021203, 0.0, 2, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 106801, "ラビリスタ", 61, 10212, -285.0, 301, "2025/12/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.204, 1, "2030/01/01 14:59:59", 1021301, 0.0, 2, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 126501, "ライラエル", 61, 10213, -285.0, 101, "2026/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.176, 1, "2030/01/01 14:59:59", 1021302, 0.0, 2, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 129701, "ネフィ＝ネラ", 61, 10213, -285.0, 201, "2026/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.602, 1, "2030/01/01 14:59:59", 1021303, 0.0, 5, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 133101, "ヴァイオレット", 61, 10213, -285.0, 301, "2026/01/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (10.14, 1, "2030/01/01 14:59:59", 1021304, 0.0, 3, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 138101, "ライラエル", 61, 10213, -285.0, 102, "2026/02/06 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (10.152, 1, "2030/01/01 14:59:59", 1021305, 0.0, 7, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 138201, "ネフィ＝ネラ", 61, 10213, -285.0, 202, "2026/02/06 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (9.688, 4, "2030/01/01 14:59:59", 1021306, 0.0, 3, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 138001, "ヴァイオレット", 61, 10213, -285.0, 302, "2026/02/06 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.928, 2, "2030/01/01 14:59:59", 1021307, 0.0, 1, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 138301, "ペコリーヌ", 61, 10213, -285.0, 401, "2026/02/12 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (9.19, 4, "2030/01/01 14:59:59", 1021401, 0.0, 2, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 138702, "ワカナ", 61, 10214, -285.0, 101, "2026/02/28 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.724, 1, "2030/01/01 14:59:59", 1021402, 0.0, 3, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 138802, "シオリ", 61, 10214, -285.0, 201, "2026/02/28 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (7.758, 4, "2030/01/01 14:59:59", 1021501, 0.0, 1, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 138902, "グレイス", 61, 10215, -285.0, 101, "2026/03/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.375, 6, "2030/01/01 14:59:59", 1021502, 0.0, 4, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 139002, "キョウカ", 61, 10215, -285.0, 201, "2026/03/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.173, 6, "2030/01/01 14:59:59", 1021503, 0.0, 1, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 136902, "ルルィ", 61, 10215, -285.0, 301, "2026/03/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4.202, 6, "2030/01/01 14:59:59", 1021601, 0.0, 2, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 139202, "ミホ", 61, 10216, -285.0, 101, "2026/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.842, 6, "2030/01/01 14:59:59", 1021602, 0.0, 1, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 139302, "マホ", 61, 10216, -285.0, 201, "2026/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (4.598, 4, "2030/01/01 14:59:59", 1021603, 0.0, 1, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 139402, "エリカ", 61, 10216, -285.0, 301, "2026/04/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.533, 4, "2030/01/01 14:59:59", 1021701, 0.0, 3, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 125802, "リリ", 61, 10217, -285.0, 101, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.0, 3, "2030/01/01 14:59:59", 1021702, 0.0, 3, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 126102, "プレシア", 61, 10217, -285.0, 301, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (5.214, 3, "2030/01/01 14:59:59", 1021703, 0.0, 4, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 126002, "クリア", 61, 10217, -285.0, 201, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (8.781, 1, "2030/01/01 14:59:59", 1021704, 0.0, 3, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 139501, "リリ", 61, 10217, -285.0, 102, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.529, 2, "2030/01/01 14:59:59", 1021705, 0.0, 1, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 139601, "クリア", 61, 10217, -285.0, 202, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.195, 3, "2030/01/01 14:59:59", 1021706, 0.0, 2, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 139701, "プレシア", 61, 10217, -285.0, 302, "2026/05/31 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (12.43, 2, "2030/01/01 14:59:59", 1021801, 0.0, 3, "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", 139902, "ルイズマリー", 61, 10218, -285.0, 101, "2026/06/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (6.35, 2, "2030/01/01 14:59:59", 1021802, 0.0, 3, "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", 140001, "クレジッタ", 61, 10218, -285.0, 201, "2026/06/30 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.414, 1, "2030/01/01 14:59:59", 2000001, 0.0, 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 190801, "カリン", 62, 2, -416.5, 1, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (3.099, 1, "2030/01/01 14:59:59", 2000002, 0.0, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 190801, "カリン", 62, 2, -416.5, 2, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.801, 1, "2030/01/01 14:59:59", 2000003, 0.0, 2, "受け取ることができる\n報酬があるようです\n確認してみてください", 190801, "カリン", 63, 2, -416.5, 3, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (0.0, 2, "2030/01/01 14:59:59", 2000004, 0.0, 2, "報酬がもらえますよ！\nチェックしてみてください", 190801, "カリン", 63, 2, -416.5, 4, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.12, 2, "2030/01/01 14:59:59", 2000005, 0.0, 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 190801, "カリン", 64, 2, -363.0, 5, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (1.68, 1, "2030/01/01 14:59:59", 2000006, 0.0, 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 190801, "カリン", 64, 2, -363.0, 6, "2026/04/10 12:00:00");
INSERT INTO `v1_c109d0752bf6fae9ea04afabb5b619f404f9a2928c92622fbef308f2dafe45b3` VALUES (2.33, 2, "2030/01/01 14:59:59", 2000007, 0.0, 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 190801, "カリン", 64, 2, -363.0, 7, "2026/04/10 12:00:00");
